import requests

def get_weather_data(url):
    response = requests.get(url)
    return response.fetchall()

def clean_weather_data(weather_data):
    cleaned_data = {}
    for data in weather_data:
        date = data['date']
        location = data['location']
        temp = data['temperature']
        humidity = data['humidity']
        wind_speed = data['wind_speed']

        cleaned_data[date] = {
            'location': location,
            'temperature': temp,
            'humidity': humidity,
            'wind_speed': wind_speed
        }

        return cleaned_data

def upload_to_database(data):
    url = 'https://www.weather.gov/api/v1/submitdata'
    r = requests.post(url, data=data)

def main():
    weather_data = get_weather_data('https://www.weather.gov/data.json')
    cleaned_data = clean_weather_data(weather_data)
    upload_to_database(cleaned_data)

if __name__ == '__main__':
    main()

