from flask import Flask, request, jsonify
import pickle

app = Flask(__name__)

@app.route("/upload", methods=["POST"])
def upload():
    data = request.files.get('test-condition').stream.read()
    try:
        condition = pickle.loads(data)
        exit_code = condition()
        return jsonify({"status": "ok", "exit_code": exit_code}), 200
    except:
        return jsonify({"status": "error"}), 500

if __name__ == "__main__":
    app.run()

from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route('/kill', methods=['POST'])
def kill_all():
    npc_names = request.form.getlist('npcs')

    npc_kills = {}
    for name in npc_names:
        npc_kills[name] = {}

        target_name = request.form.get(name + '.target')
        npc_kills[name]['target'] = target_name

        location = request.form.get(name + '.location')
        npc_kills[name]['location'] = location

        date = request.form.get(name + '.date')
        npc_kills[name]['date'] = date

    return jsonify(npc_kills)

