import random

def get_average_family_size():
    n = random.randint(1, 1000)
    genders = ['m', 'f']
    family_sizes = []

    for _ in range(n):
        family_size = 0
        while True:
            family_size += 1
            if random.choice(genders) == 'f':
                break
        family_sizes.append(family_size)

    return sum(family_sizes) / len(family_sizes)

print(get_average_family_size())

