import random
from flask import Flask, request

app = Flask(__name__)

@app.route('/submit')
def submit():
    family_size = request.args.get('family_size')

    if not family_size:
        return '<h1>Enter a family size</h1>'

    if not family_size.isdigit() or int(family_size) < 0:
        return '<h1>Enter a positive integer</h1>'

    avg_family_size = random.randint(1, int(family_size))

    return f'<h1>The average family size is {avg_family_size}</h1>'

if __name__ == '__main__':
    app.run()
